// ── Fetch all Pipedrive recents since last run, extract SharePoint URLs ──
// Timestamp persisted in workflow static data between executions.

const TOKEN  = $env.PIPEDRIVE_API_TOKEN;
const DOMAIN = $env.PIPEDRIVE_DOMAIN;
const SP_RE  = /https?:\/\/[a-zA-Z0-9-]+\.sharepoint\.com\/[^\s"'<>\])]+/gi;

// ── Timestamp management ────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
const now        = new Date();
const fmtDate    = d => d.toISOString().replace('T', ' ').replace(/\.\d{3}Z$/, '');

const since = staticData.lastRunTimestamp
  ? fmtDate(new Date(staticData.lastRunTimestamp))
  : fmtDate(new Date(now.getTime() - 3600_000));

// ── Robust paginated fetch ───────────────────────────────────────────
async function pipedriveGetAll(path, params = {}) {
  const all = [];
  let start = 0, page = 0;
  const MAX_PAGES = 100;

  while (page < MAX_PAGES) {
    const qs = new URLSearchParams({ api_token: TOKEN, limit: '500', start: String(start), ...params });
    const r  = await fetch(`https://${DOMAIN}/api/v1${path}?${qs}`);
    if (!r.ok) throw new Error(`Pipedrive ${path} failed – HTTP ${r.status}: ${await r.text()}`);
    const body = await r.json();

    if (Array.isArray(body.data)) all.push(...body.data);

    const pg = body.additional_data?.pagination;
    if (!pg || !pg.more_items_in_collection) break;
    start = typeof pg.next_start === 'number' ? pg.next_start : start + 500;
    page++;
    await new Promise(res => setTimeout(res, 150)); // respect rate limit
  }
  return all;
}

const allItems = await pipedriveGetAll('/recents', {
  since_timestamp: since,
  items: 'activity,note,file'
});

// Save timestamp after successful fetch so a downstream failure causes safe retry
staticData.lastRunTimestamp = now.toISOString();

// ── Extract SharePoint URLs, one output item per URL ─────────────────
const results = [];
for (const item of allItems) {
  const t = item.item_type, d = item.data || {};
  let text = '', entityType = null, entityId = null;

  if      (t === 'activity') text = [d.subject, d.note, d.description].filter(Boolean).join(' ');
  else if (t === 'note')     text = d.content || '';
  else if (t === 'file')     text = [d.name, d.url, d.description].filter(Boolean).join(' ');
  else continue;

  if      (d.deal_id)   { entityType = 'deal';   entityId = d.deal_id; }
  else if (d.person_id) { entityType = 'person'; entityId = d.person_id; }
  else if (d.org_id)    { entityType = 'org';    entityId = d.org_id; }
  if (!entityId) continue;

  for (const spUrl of [...new Set(text.match(SP_RE) || [])]) {
    results.push({ json: { spUrl, itemType: t, itemId: d.id, entityType, entityId } });
  }
}

return results;

// Base64url-encode the SharePoint URL for Graph API shares endpoint
const spUrl   = $json.spUrl;
const encoded = 'u!' + Buffer.from(spUrl).toString('base64')
  .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
return [{ json: { ...$json, graphSharesId: encoded } }];

// Merge Graph API driveItem response with original metadata from Encode SP URL.
// $json = driveItem. Use $itemIndex to pair correctly across multiple items.
const ctx = $('Encode SP URL').all()[$itemIndex].json;
return [{
  json: {
    ...$json,
    entityType: ctx.entityType,
    entityId:   ctx.entityId,
    spUrl:      ctx.spUrl
  }
}];

// TRUE branch – file: download from SharePoint SAS URL, upload to Pipedrive.
// $json already has entityType/entityId merged in by 'Merge Context'.
const TOKEN  = $env.PIPEDRIVE_API_TOKEN;
const DOMAIN = $env.PIPEDRIVE_DOMAIN;

const downloadUrl = $json['@microsoft.graph.downloadUrl'];
const fileName    = $json.name || 'sharepoint-file';
const entityField = $json.entityType === 'deal'   ? 'deal_id'
                  : $json.entityType === 'person' ? 'person_id'
                  : 'org_id';

// SAS URL is pre-authenticated — no extra headers needed
const fileResp = await fetch(downloadUrl);
if (!fileResp.ok) throw new Error(`SP download failed: HTTP ${fileResp.status}`);
const fileBuffer = Buffer.from(await fileResp.arrayBuffer());

const form = new FormData();
form.append('file', new Blob([fileBuffer]), fileName);
form.append(entityField, String($json.entityId));

const up = await fetch(
  `https://${DOMAIN}/api/v1/files?api_token=${encodeURIComponent(TOKEN)}`,
  { method: 'POST', body: form }
);
if (!up.ok) throw new Error(`Pipedrive file upload failed: HTTP ${up.status}`);
const result = await up.json();
return [{ json: result }];

// FALSE branch – folder: add a Pipedrive note with the folder link.
// $json already has entityType/entityId merged in by 'Merge Context'.
const TOKEN  = $env.PIPEDRIVE_API_TOKEN;
const DOMAIN = $env.PIPEDRIVE_DOMAIN;

const entityField = $json.entityType === 'deal'   ? 'deal_id'
                  : $json.entityType === 'person' ? 'person_id'
                  : 'org_id';

const content = `📁 SharePoint folder linked automatically\n\n`
  + `Name: ${$json.name || 'SharePoint Folder'}\n`
  + `URL: ${$json.webUrl || $json.spUrl}\n`
  + `(Added by n8n SharePoint Auto-Linker)`;

const r = await fetch(
  `https://${DOMAIN}/api/v1/notes?api_token=${encodeURIComponent(TOKEN)}`,
  {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ content, [$json.entityField]: $json.entityId })
  }
);
if (!r.ok) throw new Error(`Pipedrive note creation failed: HTTP ${r.status}`);
const result = await r.json();
return [{ json: result }];
